<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Roast My Code - AI Code Roaster</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:#0a0a0f;color:#e0e0e0;min-height:100vh}
.container{max-width:700px;margin:0 auto;padding:20px}
.header{text-align:center;padding:30px 20px;background:linear-gradient(135deg,#f12711 0%,#f5af19 100%);border-radius:20px;margin-bottom:25px}
.header h1{font-size:2em;color:#fff;margin-bottom:8px}
.header p{color:rgba(255,255,255,0.9);font-size:1em}
.back-link{display:inline-block;color:#667eea;text-decoration:none;margin-bottom:15px;font-size:0.9em}
.back-link:hover{text-decoration:underline}
.form-card{background:linear-gradient(145deg,#1a1a2e,#16213e);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:25px;margin-bottom:20px}
label{display:block;color:#ccc;font-size:0.9em;margin-bottom:6px;font-weight:500}
select,textarea,input[type="text"]{width:100%;padding:10px 14px;background:#0d1117;border:1px solid rgba(255,255,255,0.15);border-radius:10px;color:#e0e0e0;font-size:0.95em;margin-bottom:15px;font-family:inherit}
select:focus,textarea:focus,input:focus{outline:none;border-color:#667eea}
textarea{min-height:120px;resize:vertical}
button[type="submit"]{width:100%;padding:12px;background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;border:none;border-radius:12px;font-size:1em;font-weight:bold;cursor:pointer;transition:all 0.3s}
button[type="submit"]:hover{transform:translateY(-2px);box-shadow:0 5px 20px rgba(102,126,234,0.3)}
.result{background:#0d1117;border:1px solid rgba(255,255,255,0.1);border-radius:12px;padding:20px;margin-top:15px;white-space:pre-wrap;line-height:1.6;display:none}
.loading{text-align:center;padding:20px;display:none}
.loading::after{content:'Generating...';color:#667eea;font-size:1.1em}
.footer{text-align:center;padding:15px;color:#666;font-size:0.8em;margin-top:10px}
.footer a{color:#667eea;text-decoration:none}

textarea#code{font-family:'Courier New',monospace;font-size:0.85em;min-height:200px;tab-size:2}
.result{background:#1a0a0a;border-color:rgba(241,39,17,0.3)}
</style>
</head><body>
<div class="container">
<a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" class="back-link">&larr; Back to AI Tools Hub</a>
<div class="header"><h1>&#128293; Roast My Code</h1><p>Get your code hilariously roasted by AI</p></div>

<div style="background:linear-gradient(135deg,#f093fb 0%,#f5576c 50%,#ff9a56 100%);border-radius:14px;padding:18px 22px;margin:20px 0;position:relative;overflow:hidden">
<div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;position:relative;z-index:1">
<div>
<strong style="color:#fff;font-size:1.05em">&#11088; Get the n8n AI Templates Bundle</strong>
<p style="color:rgba(255,255,255,0.9);font-size:0.85em;margin-top:3px">Production-ready workflows including this tool and more - $4.99</p>
</div>
<a href="https://payhip.com/b/sCTo9" target="_blank" style="background:rgba(255,255,255,0.95);color:#e0457b;padding:8px 20px;border-radius:20px;text-decoration:none;font-weight:bold;font-size:0.9em;white-space:nowrap">Get Templates</a>
</div>
</div>

<div class="form-card">
<form id="roastForm" onsubmit="generate(event)">
<label>Roast Level</label>
<select name="level" id="level">
<option value="mild">Mild - Gentle teasing</option>
<option value="medium" selected>Medium - Solid burns</option>
<option value="savage">Savage - No mercy</option>
</select>
<label>Programming Language</label>
<select name="language" id="language">
<option value="javascript">JavaScript</option>
<option value="python">Python</option>
<option value="typescript">TypeScript</option>
<option value="java">Java</option>
<option value="cpp">C++</option>
<option value="csharp">C#</option>
<option value="go">Go</option>
<option value="rust">Rust</option>
<option value="php">PHP</option>
<option value="ruby">Ruby</option>
<option value="other">Other</option>
</select>
<label>Paste Your Code (if you dare)</label>
<textarea name="code" id="code" placeholder="Paste your code here... we promise to be brutally honest." required></textarea>
<button type="submit">&#128293; Roast It!</button>
</form>
<div class="loading" id="loading"></div>
<div class="result" id="result"></div>
</div>

<div style="text-align:center;padding:18px;background:linear-gradient(145deg,#1a1a2e,#16213e);border:1px solid rgba(255,255,255,0.1);border-radius:14px;margin-top:20px">
<p style="color:#aaa;font-size:0.85em;margin-bottom:8px">&#9829; Like this tool? Check out our premium templates and resources</p>
<a href="https://payhip.com/ArmanisDevTools" target="_blank" style="color:#667eea;text-decoration:none;font-weight:bold;font-size:0.9em">Visit Our Store</a>
<span style="color:#444;margin:0 8px">|</span>
<a href="https://crazeemedia.app.n8n.cloud/webhook/ai-tools" style="color:#667eea;text-decoration:none;font-size:0.9em">All Tools</a>
<span style="color:#444;margin:0 8px">|</span>
<a href="https://ko-fi.com/armanidev" target="_blank" style="color:#667eea;text-decoration:none;font-size:0.9em">Support on Ko-fi</a>
</div>

<div class="footer"><p>Built by <a href="https://github.com/acunningham-ship-it">Armani</a> | <a href="https://payhip.com/ArmanisDevTools">Shop Templates</a></p></div>
</div>
<script>
async function generate(e) {
  e.preventDefault();
  const loading = document.getElementById('loading');
  const result = document.getElementById('result');
  loading.style.display = 'block';
  result.style.display = 'none';
  try {
    const resp = await fetch('https://crazeemedia.app.n8n.cloud/webhook/roast-code-api', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        level: document.getElementById('level').value,
        language: document.getElementById('language').value,
        code: document.getElementById('code').value
      })
    });
    const data = await resp.json();
    result.textContent = data.roast || data.text || data.output || JSON.stringify(data);
    result.style.display = 'block';
  } catch(err) {
    result.textContent = 'Error: ' + err.message;
    result.style.display = 'block';
  }
  loading.style.display = 'none';
}
</script>
</body></html>

